    <script>
    import {
        defineComponent,
    } from '@vue/composition-api'
    import Schema from "@/views/Company/CompanyHoliday/CompanyHolidaySchema";
    import {
        extend,
        ValidationObserver,
        ValidationProvider
    } from 'vee-validate';
    import {
        ConvertCustomFieldIntoDynamicFormObj,
        ConvertDynamicFormObjToCustomFieldObj
    } from "@/assets/common/vue-common.js"
    import DataService from "@/services/DataService";
    import Toggle from '@vueform/toggle';
    import moment from 'moment'
    extend('required', {
        validate(value) {
            console.log("checkk")
            return {
                required: true,
                valid: ['', null, undefined].indexOf(value) === -1
            };
    
        },
        message: 'The {_field_} is required'
        ///computesRequired: true
    });
    export default defineComponent({
       // name: "Manage Departemts",
        components: {
            ValidationObserver,
            ValidationProvider,
            Toggle
        },
        props: {
            CompanyHolidayData: {
                type: Array,
            },
            addApiUrl: {
                type: String
            },
            emitName: {
                type: String
            },
            moduleName: {
                type: String
            },
            subModule: {
                type: String
            },
            title: {
                type: String
            },
            recordId: {
                type: Number
            },
            addUserGuide:{
                type: String
            }
        },
        
        data() {
            return {
                startTime: null,
                endTime: null,
                hoursDifference: null,  
                fileData:[],  
                searchCondition: '',
                CompanyHolidayListData: [],
                SearchHolidayFields: Schema.topSearchHolidaySchema,
                holidayColumnNames: Schema.holidayColumnSchema,       
                editor: this.CLASSIC_EDITOR,
                department: {
                    name: '',
                    status: {
                        name: "active",
                        id: 1
                    },
                    visibaleToclients: false,
                    visibaleToTicting: false,
                    description: '',
                },
                buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                    onClick: this.SaveHolidayBank,
                },   
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.closePopup,
                }],
                FormSchema: [
                    {
                        layoutType: "triple",
                        Data: [
                            {
                        astype: "SearchableSelectField",
                        label: this.$t('Location'),
                        name: "Location",
                        value: "",
                        placeholder: "Select Location Name",
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            actionButtons: {
                            selectAll: true,
                            clear: true},
                            groupFields: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            statusFieldConfig: {
                                fieldName: 'status',
                                activeValues: ['Active', 'active'],
                                inactiveValues: ['Inactive', 'inactive'],
                                activeColor: '#28a745',
                                inactiveColor: '#dc3545'
                            },
                        },
                        validationRules: {
                            "required": true
                        },
                    }, {
                                astype: "CheckBoxField",
                                label: this.$t('AddHolidayIn'),
                                name: "HolidayList",
                                value: "Company",
                                placeholder: "",
                                config: {
                                    options: [{name:"Customer",value:"Company"},{name:"Contract",value:"Client"}],
                                    showAddIcon: false,
                                    onChange: this.GetCheckBoxValue
                                },
                                 validationRules: {
                                        "required": true
                                 },
                            },{
                                astype: "RadioField",
                                label: this.$t('SelectYear'),
                                name: "SelectYear",
                                value: "2026",
                                placeholder: "",
                                visibility: true,
                                config: {
                                    options: [{
                                        value: 2025,
                                        name: "Preview Year (2025)"
                                    },
                                    {
                                        value: 2026,
                                        name: "Current Year (2026)"
                                    },
                                    {
                                        value: 2027,
                                        name: "Next Year (2027)"
                                    }],
                                    showAddIcon: false
                                },
                                validationRules: "",
                            },
                        ]
                    },
                    {
                        layoutType:'single',
                        Data:[
                            {
                                astype: "SlotField",
                                label: "",
                                name: "AvailableClientsLang",
                                value: "",
                                placeholder: "",
                                config: {
                                    options: [],
                                    showAddIcon: false,
                                },
                                validationRules: "",
                            },
                        ]
                    },
                    {
                        layoutType:'single',
                        Data:[
                            {
                                astype: "SlotField",
                                label: "",
                                name: "AvailableHolidayListing",
                                value: "",
                                placeholder: "",
                                config: {
                                    options: [],
                                    showAddIcon: false,
                                },
                                validationRules: "",
                            },
                        ]
                    }
                ],
                isLoading: false,
                showContractDiv:false,
                GetSaveHolidayData:[],
                SortBy: '',
                SortExp: 'ASC',
                PageSize: "10",
                PageNumber: "1",
                availableClients: [],
                selectedClients: [],
                availableClientsSearch: '',
                selectedClientsSearch: '',
                 LegendArray: [{
                class: 'legends_medium colorboxsquare',
                text: this.$t('HolidayBank')
                }, {
                    class: 'legend-pending colorboxsquare',
                    text:this.$t(`ManualHoliday`)
                }],
            }
    
        },
        created:async function () {
            await this.FetchData();
            await this.GetLocationDDL();
        },
        methods: {
            checkForAutoCreateEnable(getRowData){
                var vm = this;
                var checkexist = vm.GetSaveHolidayData.find(x=> x.holidaybank_id === getRowData.Bank_Holiday_Id);
                if(checkexist != undefined){
                    checkexist.IsRecurring = getRowData.IsRecurring == false ? 0 : 1;
                    checkexist.IsFixedDate = getRowData.IsFixedDate;
                }else{
                    vm.GetSaveHolidayData.push({
                        client_id:'',
                        locations:vm.FormSchema[0].Data[0].value,
                        holidaybank_id:getRowData.Bank_Holiday_Id,
                        country_id:getRowData.Bank_Holiday_Country_Id,
                        IsRecurring:getRowData.IsRecurring == false ? 0 : 1,
                        IsFixedDate:getRowData.IsFixedDate
                    })
                }
            },
            async GetLocationDDL(){
                var vm = this;
                var url=`RequestFrom=${'COMPANY_PARENT_LOCATION'}`;
                await DataService.CompanyHolidayMultipleLocation(url).then(function (response) {
                    if (response.data.result != "" && response.data.result != null) {
                        if (response.data.result.length > 0) {
                            response.data.result.forEach(element => {                        
                                vm.FormSchema[0].Data[0].config.options.push({
                                     description: null,
                                    displayValue: element.LOCATION_NAME,
                                    groupText: null,
                                    groupValue: null,
                                    metaData: null,
                                    text: element.LOCATION_NAME,
                                    value: element.COMPANY_LOCATION_ID
                                })
                            });
                            vm.$refs.dynamicForm.UpdateKeyValue();
                        }                        
                    }
                });
            },
            leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                const searchCondition = value.searchCondition;
                const match = searchCondition.match(/'([^%']+)%'/);;
                const result = match ? match[1] : null;
                this.searchCondition = result;
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
        },
        actionButtonClick: function (callbackfunction, item, index, event) {  
        },
            async FetchData() {
                var vm = this;
                vm.isLoading = true;
                var url = `moduleName=${vm.moduleName}&subModuleCode=${vm.subModule}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}`
                if (!vm.isBlank(this.searchCondition)) {
                url += `&search=${this.searchCondition}`;
                }
                await DataService.HolidayBankListing(url).then(function(response) {
                    console.log(response);
                    vm.isLoading = false;
                    if(response.data != '' && response.data != null) {
                        if(response.data.result.length > 0) {
                            console.log(response.data.result);
                            vm.holidayColumnNames.forEach(column=>{
                                if(column.COLUMN_NAME == "Bank_Holiday_Type" || column.COLUMN_NAME == "IsRecurring"){
                                    column.settings = {
                                        isInSlot: true,
                                    };
                                }
                            })
                            vm.CompanyHolidayListData = response.data.result;
                              vm.CompanyHolidayListData.forEach(item => {
                                item.additionalClass = '';
                                if (item.IsManual ==1) {
                                    item.additionalClass='high-bar';
                                }else{
                                    item.additionalClass='medium-bar';
                                }
                              
                            });
                            // vm.holidayColumnNames = Object.keys(vm.CompanyHolidayListData[0]);
                            // console.log(vm.holidayColumnNames);
                        }
                    }
                })
            },
            async SaveHolidayBank() {
                var vm = this;
                vm.isLoading = true;
                
                // Collect selected bank holidays - check both GetSaveHolidayData and checked checkboxes
                var selectedBankHolidays = [];
                
                // Get checked holidays from the list (using jQuery to find checked checkboxes like MVC)
                var checkedHolidayIds = [];
                if (typeof $ !== 'undefined') {
                    $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                        checkedHolidayIds.push($(this).val());
                    });
                }
                
                // Build selectedBankHolidays array from checked holidays
                vm.CompanyHolidayListData.forEach(function(holiday) {
                    var holidayId = holiday.Bank_Holiday_Id ? holiday.Bank_Holiday_Id.toString() : '';
                    var isChecked = checkedHolidayIds.includes(holidayId) || 
                                   vm.GetSaveHolidayData.some(function(item) {
                                       return item.holidaybank_id === holiday.Bank_Holiday_Id;
                                   });
                    
                    if (isChecked) {
                        var holidayData = vm.GetSaveHolidayData.find(function(item) {
                            return item.holidaybank_id === holiday.Bank_Holiday_Id;
                        });
                        
                        var countryId = holiday.Bank_Holiday_Country_Id || (holidayData ? holidayData.country_id : null);
                        var holidaybankId = holiday.Bank_Holiday_Id;
                        var selectedLocations = vm.FormSchema[0].Data[0].value || '';
                        
                        // Get IsRecurring and IsFixedDate from holidayData or holiday row
                        var isRecurring = false;
                        var isFixed = false;
                        
                        if (holidayData) {
                            isRecurring = holidayData.IsRecurring === 1 || holidayData.IsRecurring === true;
                            isFixed = holidayData.IsFixedDate === 1 || holidayData.IsFixedDate === true;
                        } else {
                            // Use default values from holiday row if not in GetSaveHolidayData
                            isRecurring = holiday.IsRecurring === true || holiday.IsRecurring === 1;
                            isFixed = holiday.IsFixedDate === 1 || holiday.IsFixedDate === true;
                        }
                        
                        selectedBankHolidays.push({
                            country_id: countryId,
                            holidaybank_id: holidaybankId,
                            locations: selectedLocations,
                            IsRecurring: isRecurring,
                            IsFixed: isFixed
                        });
                    }
                });
                
                // Validation: Check if any holiday is selected
                if (selectedBankHolidays.length === 0) {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t("SelectHolidayBank"), "warning", true, vm.$t("Alert"));
                    return;
                }
                
                // Validation: Check location selection (if not existing mapping)
                // Note: existingMapping logic would need to be added if radio buttons are present
                var locationValue = vm.FormSchema[0].Data[0].value;
                if (!locationValue || locationValue === '' || locationValue === '0') {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t('Location') + '' + vm.$t('Required'), "warning", true, vm.$t("Alert"));
                    return;
                }
                
                // Validation: Check "Add Holiday In" checkbox selection
                var holidayListValue = vm.FormSchema[0].Data[1].value;
                if (!holidayListValue || (Array.isArray(holidayListValue) && holidayListValue.length === 0)) {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t('AddHolidayIn') + ' ' + vm.$t('Required'), "warning", true, vm.$t("Alert"));
                    return;
                }
                
                // Determine isForCompany and isForContract
                var isForCompany = 0;
                if (Array.isArray(holidayListValue) && holidayListValue.includes('Company')) {
                    isForCompany = 1;
                } else if (holidayListValue === 'Company') {
                    isForCompany = 1;
                }
                
                var isForContract = 0;
                var clientIds = '';
                
                if (Array.isArray(holidayListValue) && holidayListValue.includes('Client')) {
                    isForContract = 1;
                    // Get selected client IDs from visiblecolumn checkboxes
                    if (vm.showContractDiv) {
                        clientIds = vm.getSelectedClientIds();
                        if (!clientIds || clientIds === '') {
                            vm.isLoading = false;
                            vm.ShowAlert(vm.$t('AddClientAlert') || 'Please select at least one client', "warning", true, vm.$t("Alert"));
                            return;
                        }
                    }
                } else if (holidayListValue === 'Client') {
                    isForContract = 1;
                    if (vm.showContractDiv) {
                        clientIds = vm.getSelectedClientIds();
                        if (!clientIds || clientIds === '') {
                            vm.isLoading = false;
                            vm.ShowAlert(vm.$t('AddClientAlert') || 'Please select at least one client', "warning", true, vm.$t("Alert"));
                            return;
                        }
                    }
                }
                
                // Get year
                var year = parseInt(vm.FormSchema[0].Data[2].value) || new Date().getFullYear();
                
                // Status (default to 1001 if not available)
                var status = 1001;
                
                // Existing mapping (default to false if not available)
                var existingMapping = false;
                
                // Build data object matching MVC structure
                var saveData = {
                    client_id: clientIds || '',
                    selectedBankHolidays: selectedBankHolidays,
                    isforcompany: isForCompany,
                    isforcontract: isForContract,
                    year: year,
                    status: status,
                    existingMapping: existingMapping
                };
                
                // Call SaveBankHoliday API
                var jsonData = JSON.stringify(saveData);
                DataService.SaveBankHoliday(jsonData)
                .then(function(response) {
                    vm.isLoading = false;
                    if (response && response.data) {
                        // Check response structure
                        if (response.data) {
                            vm.ShowAlert(vm.$t('HolidayImportedSuccessfully') || vm.$t('SavedSuccessfully'), "success", false, vm.$t("Alert"));
                            vm.$emit('close');
                            // Reload data if needed
                           vm.$parent.FetchData();
                        } else {
                            vm.ShowAlert(vm.$t('ErrorWhileSavingRecords'), "danger", false, vm.$t("Alert"));
                        }
                    } else {
                        vm.ShowAlert(vm.$t('ErrorWhileSavingRecords'), "danger", false, vm.$t("Alert"));
                    }
                })
                .catch(function(error) {
                    vm.isLoading = false;
                    console.error('Error saving holiday bank:', error);
                    vm.ShowAlert(vm.$t('ErrorWhileSavingRecords'), "danger", false, vm.$t("Alert"));
                });
            },

            closePopup() {
                this.$emit('close')
    
            },
            GetCheckBoxValue(){
                var vm = this;
               if (Array.isArray(vm.FormSchema[0].Data[1].value) &&
                    vm.FormSchema[0].Data[1].value.includes('Client')) {
                    vm.showContractDiv = true;
                    vm.loadAvailableClients();

                } else {
                    vm.showContractDiv = false;
                }
            },
             async loadAvailableClients() {
                            const vm = this;
                            vm.isLoading= true;
                            try {
                                const url = 'type=CLIENT&projectOrClientId';
                                const response = await DataService.GetClientsAndProjects(url);
                                if (response?.data?.result) {
                                    const responseData = JSON.parse(response.data.result).data;
                                    if (Array.isArray(responseData) && responseData.length > 0) {
                                        vm.availableClients = responseData
                                            .filter(item => item.Name && item.Id && typeof item.Id === 'string' && item.Id.trim() !== '')
                                            .map(item => ({
                                                id: item.Id.split('^')[0],
                                                name: item.Name,
                                                isSelected: false
                                            }));
                                        vm.renderClientLists();
                                    }
                                     vm.isLoading= false;
                                }
                            } catch (error) {
                                console.error('Error loading clients:', error);
                            }
                        },
                        renderClientLists() {
                            const vm = this;
                            this.$nextTick(() => {
                                // Render available clients
                                const availableList = document.querySelector('#columns ul.list-group');
                                const selectedList = document.querySelector('#visiblecolumn');
                                
                                if (availableList) {
                                    availableList.innerHTML = '';
                                    const filteredAvailable = vm.getFilteredAvailableClients();
                                    if (filteredAvailable.length === 0) {
                                        availableList.innerHTML = '<li id="norecordAvailable" class="norecords list-group-item" style="display: block;"><div class="text-danger text-center no-record">No record(s) found</div></li>';
                                    } else {
                                        filteredAvailable.forEach(client => {
                                            const li = document.createElement('li');
                                            li.className = 'list-group-item ui-sortable-handle';
                                            li.innerHTML = `
                                                <div class="custom-control custom-checkbox">
                                                    <input type="checkbox" class="custom-control-input client-checkbox" id="chk_avail_${client.id}" data-client-id="${client.id}" ${client.isSelected ? 'checked' : ''}>
                                                    <label class="custom-control-label" for="chk_avail_${client.id}">${client.name}</label>
                                                </div>
                                            `;
                                            availableList.appendChild(li);
                                        });
                                    }
                                }
                                
                                if (selectedList) {
                                    selectedList.innerHTML = '';
                                    const filteredSelected = vm.getFilteredSelectedClients();
                                    if (filteredSelected.length === 0) {
                                        selectedList.innerHTML = '<li id="norecordVisibleColumn" class="norecords list-group-item ui-sortable-handle"><div class="text-danger text-center no-record">No record(s) found</div></li>';
                                    } else {
                                        filteredSelected.forEach(client => {
                                            const li = document.createElement('li');
                                            li.className = 'list-group-item ui-sortable-handle';
                                            li.innerHTML = `
                                                <div class="custom-control custom-checkbox">
                                                    <input type="checkbox" class="custom-control-input client-checkbox" id="chk_sel_${client.id}" data-client-id="${client.id}" ${client.isSelected ? 'checked' : ''}>
                                                    <label class="custom-control-label" for="chk_sel_${client.id}">${client.name}</label>
                                                </div>
                                            `;
                                            selectedList.appendChild(li);
                                        });
                                    }
                                }
                                
                                vm.attachClientEventHandlers();
                            });
                        },
                        getFilteredAvailableClients() {
                            const search = this.availableClientsSearch.toLowerCase();
                            return this.availableClients.filter(client => 
                                !this.selectedClients.some(sel => sel.id === client.id) &&
                                client.name.toLowerCase().includes(search)
                            );
                        },
                        getFilteredSelectedClients() {
                            const search = this.selectedClientsSearch.toLowerCase();
                            return this.selectedClients.filter(client => 
                                client.name.toLowerCase().includes(search)
                            );
                        },
                        attachClientEventHandlers() {
                            const vm = this;
                            
                            // Search handlers
                            const availableSearchInput = document.getElementById('txtAvailableColumnsInSetup');
                            const selectedSearchInput = document.getElementById('txtSelectedColumnsInSetup');
                            
                            if (availableSearchInput) {
                                availableSearchInput.oninput = function() {
                                    vm.availableClientsSearch = this.value;
                                    vm.renderClientLists();
                                };
                            }
                            
                            if (selectedSearchInput) {
                                selectedSearchInput.oninput = function() {
                                    vm.selectedClientsSearch = this.value;
                                    vm.renderClientLists();
                                };
                            }
                            
                            // Search button handlers
                            const searchAvailableBtn = document.getElementById('ancSearchAvailableColumnsInSetup');
                            const clearAvailableBtn = document.getElementById('ancClearAvailableColumnsInSetup');
                            const searchSelectedBtn = document.getElementById('ancSearchSelectedColumnsInSetup');
                            const clearSelectedBtn = document.getElementById('ancClearSelectedColumnsInSetup');
                            
                            if (searchAvailableBtn) {
                                searchAvailableBtn.onclick = () => vm.renderClientLists();
                            }
                            if (clearAvailableBtn) {
                                clearAvailableBtn.onclick = () => {
                                    vm.availableClientsSearch = '';
                                    if (availableSearchInput) availableSearchInput.value = '';
                                    vm.renderClientLists();
                                };
                            }
                            if (searchSelectedBtn) {
                                searchSelectedBtn.onclick = () => vm.renderClientLists();
                            }
                            if (clearSelectedBtn) {
                                clearSelectedBtn.onclick = () => {
                                    vm.selectedClientsSearch = '';
                                    if (selectedSearchInput) selectedSearchInput.value = '';
                                    vm.renderClientLists();
                                };
                            }
                            
                            // Move button handlers
                            const moveRightBtn = document.getElementById('aColumnArrow');
                            const moveAllRightBtn = document.getElementById('aMoveAllColumnArrow');
                            const moveLeftBtn = document.getElementById('aColumnRemoveArrow');
                            const moveAllLeftBtn = document.getElementById('aMoveAllColumnRemoveArrow');
                            
                            if (moveRightBtn) {
                                moveRightBtn.onclick = () => vm.moveSelectedClientsRight();
                            }
                            if (moveAllRightBtn) {
                                moveAllRightBtn.onclick = () => vm.moveAllClientsRight();
                            }
                            if (moveLeftBtn) {
                                moveLeftBtn.onclick = () => vm.moveSelectedClientsLeft();
                            }
                            if (moveAllLeftBtn) {
                                moveAllLeftBtn.onclick = () => vm.moveAllClientsLeft();
                            }
                            
                            // Checkbox handlers
                            document.querySelectorAll('#columns .client-checkbox').forEach(checkbox => {
                                checkbox.onchange = function() {
                                    const clientId = this.getAttribute('data-client-id');
                                    const client = vm.availableClients.find(c => c.id === clientId);
                                    if (client) {
                                        client.isSelected = this.checked;
                                    }
                                };
                            });
                            
                            document.querySelectorAll('#visiblecolumn .client-checkbox').forEach(checkbox => {
                                checkbox.onchange = function() {
                                    const clientId = this.getAttribute('data-client-id');
                                    const client = vm.selectedClients.find(c => c.id === clientId);
                                    if (client) {
                                        client.isSelected = this.checked;
                                    }
                                };
                            });
                        },
                        moveSelectedClientsRight() {
                            const selected = this.availableClients.filter(c => c.isSelected && !this.selectedClients.some(sel => sel.id === c.id));
                            selected.forEach(client => {
                                client.isSelected = false;
                                if (!this.selectedClients.some(sel => sel.id === client.id)) {
                                    this.selectedClients.push({...client});
                                }
                            });
                            this.renderClientLists();
                        },
                        moveAllClientsRight() {
                            const available = this.getFilteredAvailableClients();
                            available.forEach(client => {
                                if (!this.selectedClients.some(sel => sel.id === client.id)) {
                                    this.selectedClients.push({...client, isSelected: false});
                                }
                            });
                            this.renderClientLists();
                        },
                        moveSelectedClientsLeft() {
                            const selected = this.selectedClients.filter(c => c.isSelected);
                            selected.forEach(client => {
                                const index = this.selectedClients.findIndex(c => c.id === client.id);
                                if (index > -1) {
                                    this.selectedClients.splice(index, 1);
                                }
                            });
                            this.renderClientLists();
                        },
                        moveAllClientsLeft() {
                            this.selectedClients = [];
                            this.renderClientLists();
                        },
                        getSelectedClientIds() {
                            return this.selectedClients.map(c => c.id).join(',');
                        },
    
        }
    
    });
    </script>
    